const assert = require('assert');
const path = require('path');
const fs = require('fs');
const AnnotationParser = require('../../../src/core/AstAnnotationParser');
const AnnotationRegistry = require('../../../src/core/AnnotationRegistry');

const testDirRoot = path.join(__dirname, 'temp');
fs.mkdirSync(testDirRoot, { recursive: true });

describe('AnnotationParser (Unit)', () => {
  let processedTargets = [];

  before(() => {
    /**
     * Dummy-Annotation für Testzwecke.
     */
    class DummyAnnotation {
      constructor(params) {
        Object.assign(this, params);
      }
    }

    /**
     * Dummy-Prozessor, der die Annotation und das Ziel während der Scan-Phase speichert.
     */
    class DummyProcessor {
      processScan(annotation, target, propertyName) {
        processedTargets.push({ annotation, target, propertyName });
      }
    }

    AnnotationRegistry.register('Dummy', DummyAnnotation, new DummyProcessor());
  });

  beforeEach(() => {
    processedTargets = [];
  });

  after(() => {
    fs.rmSync(testDirRoot, { recursive: true, force: true });
  });

  it('should parse annotation on class with parameters', () => {
    const filePath = path.join(testDirRoot, 'ClassTest.js');
    fs.writeFileSync(filePath, `
      /**
       * @Dummy(name="ClassService", version=1)
       */
      class ClassService {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 1);
    assert.strictEqual(processedTargets[0].target.name, 'ClassService');
    assert.strictEqual(processedTargets[0].annotation.name, 'ClassService');
    assert.strictEqual(processedTargets[0].annotation.version, '1');

    fs.unlinkSync(filePath);
  });

  it('should parse annotation on function with parameters', () => {
    const filePath = path.join(testDirRoot, 'FunctionTest.js');
    fs.writeFileSync(filePath, `
      /**
       * @Dummy(name="FunctionService", flag=true)
       */
      function FunctionService() {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 1);
    assert.strictEqual(processedTargets[0].target.name, 'FunctionService');
    assert.strictEqual(processedTargets[0].annotation.name, 'FunctionService');
    assert.strictEqual(processedTargets[0].annotation.flag, 'true');

    fs.unlinkSync(filePath);
  });

  it('should parse multiple annotations in one file', () => {
    const filePath = path.join(testDirRoot, 'MultiTest.js');
    fs.writeFileSync(filePath, `
      /**
       * @Dummy(name="One")
       */
      class One {}

      /**
       * @Dummy(name="Two", active=false)
       */
      function Two() {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 2);
    assert.strictEqual(processedTargets[0].target.name, 'One');
    assert.strictEqual(processedTargets[0].annotation.name, 'One');
    assert.strictEqual(processedTargets[1].target.name, 'Two');
    assert.strictEqual(processedTargets[1].annotation.name, 'Two');
    assert.strictEqual(processedTargets[1].annotation.active, 'false');

    fs.unlinkSync(filePath);
  });

  it('should parse property-level annotation', () => {
    const filePath = path.join(testDirRoot, 'PropertyTest.js');
    fs.writeFileSync(filePath, `
      class Service {
        /**
         * @Dummy(name="PropService")
         */
        myProp;
      }
    `);

    AnnotationParser.parseFile(filePath);

  console.log('DEBUG processedTargets[0]:', processedTargets[0]);
  assert.strictEqual(processedTargets.length, 1);
  assert.strictEqual(processedTargets[0].target.className, 'Service');
  assert.strictEqual(processedTargets[0].target.name, 'myProp');
  assert.strictEqual(processedTargets[0].propertyName, 'myProp');
  assert.strictEqual(processedTargets[0].annotation.name, 'PropService');

    fs.unlinkSync(filePath);
  });

  it('should ignore unregistered annotation', () => {
    const filePath = path.join(testDirRoot, 'UnknownTest.js');
    fs.writeFileSync(filePath, `
      /**
       * @Unknown(name="Ghost")
       */
      class Ghost {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 0);

    fs.unlinkSync(filePath);
  });

  it('should ignore comments without annotations', () => {
    const filePath = path.join(testDirRoot, 'NoAnnotation.js');
    fs.writeFileSync(filePath, `
      /**
       * Just a regular comment
       */
      class Nothing {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 0);

    fs.unlinkSync(filePath);
  });

  it('should handle malformed parameters gracefully', () => {
    const filePath = path.join(testDirRoot, 'Malformed.js');
    fs.writeFileSync(filePath, `
      /**
       * @Dummy(name, version=)
       */
      class Broken {}
    `);

    AnnotationParser.parseFile(filePath);

    assert.strictEqual(processedTargets.length, 1);
    assert.strictEqual(processedTargets[0].annotation.name, undefined);
    assert.strictEqual(processedTargets[0].annotation.version, undefined);

    fs.unlinkSync(filePath);
  });
});
